import React from 'react';
import { useState, useEffect } from 'react';
import './App.css';

function SearchBar({ filterText, onFilterTextChange }) {
  return (

    <input
      type="text"
      className="form-control mr-sm-0"
      value={filterText} placeholder="Search Destinations"
      style={{ width: '30%' }}
      onChange={(e) => onFilterTextChange(e.target.value)} />
  );
}

function Cards({ property }) {

  const [showDetails, setShowDetails] = useState(false);
  const onClick = (showDetails) => setShowDetails(!showDetails)

  return (
    <>
      <div className="card my-2" onClick={()=>setShowDetails(!showDetails)}>
        <img className="card-img-top" src={property.thumbnail} alt="Card image cap" />
        <div className="card-body">
          <h5 className="card-title"><b>{property.title} </b></h5>
          <span className="card-text"><u>{property.location}</u></span><br />
          {!showDetails ? <><span className="card-text">{property.shortDescription}</span><br /></> : null}
          <span className="card-text"><b>${property.nightlyFee}</b> per night</span><br />
          {showDetails ? <CardDetails property={property} /> : null}
        </div>
      </div>
    </>
  );
}

function CardDetails({ property }) {
  return (
    <>
      <span className="card-text">{property.description}</span><br />
      <span className="card-text"><b><u>Guests:</u> {property.beds}</b></span><br />
      <span className="card-text"><b><u>Bedrooms:</u> {property.bedrooms}</b></span><br />
      <span className="card-text"><b><u>Beds:</u> {property.beds}</b></span><br />
      <span className="card-text"><b><u>Guests:</u> {property.beds}</b></span><br />
      <span className="card-text"><b><u>Baths:</u> {property.baths}</b></span><br />
      <span className="card-text"><b><u>Cleaning Fees:</u> ${property.cleaningFee}</b></span><br />
      <span className="card-text"><b><u>Service Fees:</u> ${property.serviceFee}</b></span><br />
      <span className="card-text"><b><u>Ameneties:</u></b> {property.amenities}</span><br />
      <span className="card-text"><b><u>Stars:</u></b> {property.reviews.stars}</span><br />
      <span className="card-text"><b><u>Total Reviews:</u></b> {property.reviews.totalReviews}</span><br />
    </>
  );
}


function CardItems({ properties, filterText }) {

  const cards = [];

  properties.forEach((property) => {
    if (property.title.toLowerCase().indexOf(filterText.toLowerCase()) === -1) {
      if (property.city.toLowerCase().indexOf(filterText.toLowerCase()) === -1) {
        return;
      }
    }
    cards.push(
      <Cards
        property={property}
        key={property.id} />
    );
  });

  return (
    <>
      {cards}
    </>
  );
}


export default function App() {
  const [filterText, setFilterText] = useState('');
  const [properties, setProperties] = useState([]);

  useEffect(() => {
    fetch("http://localhost:9000/properties")
      .then((response) => response.json())
      .then((properties) => {
        console.log(properties);
        setProperties(properties);
      })
      .catch((err) => {
        console.log(err.message);
      }); 
  }, []);

  return (
    <div className="Home">
      <script src="https://cdn.jsdelivr.net/npm/bootstrap@5.2.1/dist/js/bootstrap.bundle.min.js"
        integrity="sha384-u1OknCvxWvY5kfmNBILK2hRnQC3Pr17a+RTT6rIHI7NnikvbZlHgTPOOmMi466C8" crossorigin="anonymous">
      </script>

      <header className="main-header mt-auto py-3 bg-light fixed-top">
        <nav className="navbar navbar-expand-lg fixed-top navbar-light bg-light ">
          <a className="navbar-brand" href="index.html">
            <img src="../img/logo.png" width="10%" className="align-top" />
            <span className="logo text-uppercase font-weight-bold align-bottom">Aptic</span>
          </a>
          <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbar"
            aria-controls="navbar" aria-expanded="false" aria-label="Toggle navigation">
            <span className="navbar-toggler-icon"></span>
          </button>

          <div className="collapse navbar-collapse " id="navbar">
            <form className="form-inline">
              <SearchBar
                filterText={filterText}
                onFilterTextChange={setFilterText} />

              {/* Commenting the below code as it is not required for assignment 2 */}

              {/* <input className="form-control mr-sm-0" style={{ width: '30%' }} type="text"
                placeholder="Search Destinations" aria-label="Place" /> */}
              <input className="form-control mr-sm-0" style={{ width: '20%' }} type="text" placeholder="Arrival"
                aria-label="Arrival" onfocus="(this.type='date')" onblur="(this.type='text')" />
              <input className="form-control mr-sm-0" style={{ width: '20%' }} type="text" placeholder="Departure"
                aria-label="Departure" onfocus="(this.type='date')" onblur="(this.type='text')" />

              <li className="navbar-brand dropdown">
                <input type="button" value="Guests   &#xf007;" placeholder="Guests"
                  className="dropdown-toggle form-control mr-sm-0 placeicon" id="guests" role="button"
                  data-bs-toggle="dropdown" aria-expanded="false">
                </input>

                <ul className="dropdown-menu" style={{ borderWidth: 0 }} aria-labelledby="guests">
                  <table>
                    <tr>
                      <td className="bor">Adults</td>
                      <td className="bor"><input type="number" min="0" name="adults" /></td>
                    </tr>
                    <tr>
                      <td className="bor">Chindren</td>
                      <td className="bor"><input type="number" min="0" name="children" /></td>
                    </tr>
                    <tr>
                      <td className="bor">Pets</td>
                      <td className="bor"><input type="radio" id="pets_yes" name="pets" /> Yes
                        <input type="radio" id="pets_no" name="pets" checked /> No
                      </td>
                    </tr>
                  </table>
                </ul>
              </li>

              <button className="btn btn-outline-success my-2 my-sm-0" type="submit">Search</button>
            </form>
          </div>

          <li className="navbar-brand dropdown">
            <a className="dropdown-toggle placeicon noline" href="#" id="navbarDropdown" role="button"
              data-bs-toggle="dropdown" aria-expanded="false">
              <i className="fa-thin fa-user"></i>
            </a>

            <ul className="dropdown-menu" aria-labelledby="navbarDropdown">
              <li><a className="dropdown-item" href="#">Log In</a></li>
              <li>
                <hr className="dropdown-divider" />
              </li>
              <li><a className="dropdown-item" href="#">Sign Up</a></li>

            </ul>
          </li>
        </nav>
      </header>

      <div className="content-wrapper">
        <aside>
          {/* <!-- We have create a side menu for filters that we will be using later with the help of JS --> */}
        </aside>

        <div className="content-wrapper" style={{ marginBottom: '5%' }}>
          <main>

            <div className="jumbotron pt-5">
              <img src="../img/homepage_img2.jpeg" style={{ height: '40vw' }} alt="Homepage Image" />
              <div className="centered">
                <h1 style={{ fontSize: '2.5rem' }}>The World's Best Place for Vacation Rentals</h1>
                <p style={{ top: '65%' }}>A personal service for discerning guests who value exceptional
                  quality homes and experiences in the most desirable destinations</p>
              </div>
            </div>

            <div className="flex-container">
              <CardItems
                properties={properties}
                filterText={filterText} />
            </div>

          </main>
        </div>
      </div >


      <footer className="main-footer mt-auto py-3 bg-light fixed-bottom" style={{ marginTop: '10%' }}>
        <div style={{ marginleft: '2%', marginRight: '2%' }}>
          <span className="text-muted">&copy APTIC, a home rental website. All rights reserved</span>
          <span style={{ fontSize: '20px' }}>&#8226;</span>
          <span><a href="#">Terms & Conditions</a></span>
          <span style={{ fontSize: '20px' }}>&#8226;</span>
          <span><a href="#">Privacy Policy</a></span>
          <span style={{ float: "right", marginRight: 1 }}>
            <span><a href="#">Support</a></span>
            <span> | </span>
            <span><a href="#">Feedback</a></span>
            <span> | </span>
            <span><a href="https://www.facebook.com" target="_blank" rel="noreferrer noopener"><i
              className="fa-brands fa-facebook placeicon"></i></a></span>
            <span> | </span>
            <span><a href="https://www.instagram.com" target="_blank" rel="noreferrer noopener"
              style={{ color: "maroon" }}><i className="fa-brands fa-instagram placeicon"></i></a></span>
          </span>
        </div>

      </footer>

    </div >
  );
}
